SELECT * FROM places WHERE is_active = 1 AND category IN
#{cat}
AND latitude IS NOT NULL AND longitude IS NOT NULL

SELECT * FROM places
WHERE id = #{id}
  AND is_active = 1

SELECT * FROM places
WHERE is_active = 1

    AND category = #{category}


    AND name LIKE CONCAT('%', #{keyword}, '%')

ORDER BY name
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM places WHERE is_active = 1
AND category = #{category}
AND name LIKE CONCAT('%', #{keyword}, '%')

SELECT *, ( 6371 * 2 * ASIN(SQRT( POWER(SIN(RADIANS(latitude - #{lat}) / 2), 2) + COS(RADIANS(#{lat})) * COS(RADIANS(latitude)) * POWER(SIN(RADIANS(longitude - #{lng}) / 2), 2) )) ) AS distance_km FROM places WHERE is_active = 1 AND latitude IS NOT NULL AND longitude IS NOT NULL AND category IN
#{cat}
AND ( 6371 * 2 * ASIN(SQRT( POWER(SIN(RADIANS(latitude - #{lat}) / 2), 2) + COS(RADIANS(#{lat})) * COS(RADIANS(latitude)) * POWER(SIN(RADIANS(longitude - #{lng}) / 2), 2) )) ) <= #{radiusKm} ORDER BY distance_km
